import{_ as e,o,c as a,ag as r}from"./chunks/framework.OsDJF_Ea.js";const s="/docs/modules/noise.png",m=JSON.parse('{"title":"Noise Generator","description":"","frontmatter":{},"headers":[],"relativePath":"modules/noise.md","filePath":"modules/noise.md"}'),n={name:"modules/noise.md"};function i(d,t,l,h,u,p){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="noise-generator" tabindex="-1">Noise Generator <a class="header-anchor" href="#noise-generator" aria-label="Permalink to &quot;Noise Generator&quot;">​</a></h1><p><strong>Category:</strong> Sound Sources</p><p>Multi-type noise generator with white, pink, and brown algorithms. Use the morph control to blend smoothly between noise types, or set a fixed type. Gate input lets you start and stop the noise source externally.</p><img src="'+s+'" alt="noise module"><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>gain</strong></td><td>Output amplitude 0-1. Modulate with an LFO for tremolo, or connect an ADSR for shaped bursts.</td></tr><tr><td><strong>gate</strong></td><td>Turns noise on (1) or off (0). Connect from Button, GateIn, Clock, or Sequencer for rhythmic noise hits.</td></tr><tr><td><strong>type</strong></td><td>Selects noise color: 0 = white, 1 = pink, 2 = brown.</td></tr><tr><td><strong>morph</strong></td><td>Crossfades between noise types 0-1. White at 0, pink at 0.5, brown at 1. Connect an LFO for evolving texture.</td></tr></tbody></table><h2 id="outputs" tabindex="-1">Outputs <a class="header-anchor" href="#outputs" aria-label="Permalink to &quot;Outputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>out</strong> (audio)</td><td>Mono noise output. Route to a Filter for shaped noise, or use as a modulation source for randomness.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><p>Pink noise into a bandpass Filter makes a good wind or ocean texture. For snare-style hits, gate the noise with a short ADSR. Brown noise through a low-cutoff filter works as a slow random modulation source.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2>',11)])])}const b=e(n,[["render",i]]);export{m as __pageData,b as default};
